import 'dart:io'; import 'package:cloud_firestore/cloud_firestore.dart'; import '../../../../core/constants/firestore_collections.dart'; import '../../../../core/constants/storage_paths.dart'; import '../../../../core/services/firebase/firestore_service.dart'; import '../../../../core/services/firebase/storage_service.dart'; import '../../domain/entities/user_profile.dart'; import '../../domain/repositories/user_profile_repository.dart';
class UserProfileRepositoryImpl implements UserProfileRepository{final FirestoreService fs; final StorageService storage; const UserProfileRepositoryImpl({required FirestoreService firestoreService,required StorageService storageService}):fs=firestoreService,storage=storageService; CollectionReference<Map<String,dynamic>> get users=>fs.collection(FirestoreCollections.users); @override Stream<UserProfile?> watchProfile(String userId)=>users.doc(userId).snapshots().map((d)=>d.exists&&d.data()!=null?UserProfile.fromMap({...d.data()!,'uid':d.id}):null); @override Future<UserProfile?> getProfile(String userId) async{final d=await users.doc(userId).get(); return d.exists&&d.data()!=null?UserProfile.fromMap({...d.data()!,'uid':d.id}):null;} @override Future<void> updateProfile({required String userId,String? displayName,String? city,String? township,bool? notificationEnabled})=>users.doc(userId).set({'displayName':displayName,'city':city,'township':township,'notificationEnabled':notificationEnabled,'updatedAt':FieldValue.serverTimestamp()},SetOptions(merge:true)); @override Future<String> uploadProfilePhoto({required String userId,required File image})=>storage.uploadFile(file:image,path:StoragePaths.userProfilePhoto(userId:userId,fileName:'${DateTime.now().millisecondsSinceEpoch}.jpg'),contentType:'image/jpeg'); @override Future<void> updateProfilePhoto({required String userId,required String photoUrl})=>users.doc(userId).set({'photoUrl':photoUrl,'updatedAt':FieldValue.serverTimestamp()},SetOptions(merge:true)); @override Future<void> updateOnlineStatus({required String userId,required bool isOnline})=>users.doc(userId).set({'isOnline':isOnline,'lastSeen':FieldValue.serverTimestamp()},SetOptions(merge:true));}
